import heapq

def solve(edges: list[list[int]], online: list[bool], k: int) -> int:
    n = len(online)
    adj = [[] for _ in range(n)]
    for u, v, c in edges:
        adj[u].append((v, c))

    best_min = [-float('inf')] * n
    best_total = [0] * n
    best_min[0] = float('inf')

    heap = [(-float('inf'), 0, 0)]

    while heap:
        curr_neg_min, curr_total, u = heapq.heappop(heap)
        curr_min = -curr_neg_min

        if not online[u]:
            continue

        if curr_min < best_min[u]:
            continue

        if u == n - 1:
            return curr_min

        for v, cost in adj[u]:
            if not online[v]:
                continue
            new_min = min(curr_min, cost)
            new_total = curr_total + cost
            if new_total > k:
                continue

            if new_min > best_min[v]:
                best_min[v] = new_min
                best_total[v] = new_total
                heapq.heappush(heap, (-new_min, new_total, v))
            elif new_min == best_min[v]:
                if new_total < best_total[v]:
                    best_total[v] = new_total
                    heapq.heappush(heap, (-new_min, new_total, v))

    return -1
